import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the buffer size to avoid buffer overflow
        int bufferSize = Math.min(name.length(), 10); // Choose a suitable maximum size

        // Creating a properly sized buffer
        char[] buffer = new char[bufferSize];

        // Copying user input into the fixed-size buffer with boundary checking
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Buffer overflow successfully prevented!");
    }
}

